/**
 * Pipeline dashboard data: fallback and load from pipeline_results.json
 * (Generated by: python export_pipeline_json.py)
 * The HTML uses window.pipelineData for stats, reaction bar, charts, and network graph.
 */
(function () {
    'use strict';
    window.pipelineData = {
        stats: { impressions: 0, likes: 0, dislikes: 0, shares: 0, comments: 0 },
        reaction_bar: { liked: 0, disliked: 0, shared: 0, comment: 0, none: 0 },
        chart: {
            labels: ['T=0s', 'T=5s', 'T=10s', 'Correction', 'T=60s'],
            neutral: [33, 33, 33, 33, 33],
            skeptic: [33, 33, 33, 33, 33],
            polar: [34, 34, 34, 34, 34]
        },
        graph: null,
        shares: [],
        agents: []
    };
    // When pipeline_results.json loads, it replaces this with actual pipeline output (run: python export_pipeline_json.py)

    fetch('pipeline_results.json')
        .then(function (r) { return r.ok ? r.json() : null; })
        .then(function (data) {
            if (data && typeof data === 'object') {
                window.pipelineData = data;
            }
        })
        .catch(function () {});
})();
